import { type, type Type, type JsonSchema } from "arktype"
import { jsonSchemaToType } from "@ark/json-schema"

const JSON_SCHEMA_DRAFT_2020_12 = "https://json-schema.org/draft/2020-12/schema"

/**
 * Export an ArkType Type to a JSON Schema document (draft-2020-12).
 * The returned object includes the `$schema` field.
 */
export function exportJsonSchema(schema: Type): object {
  const jsonSchema = schema.toJsonSchema() as Record<string, unknown>
  // Ensure $schema is present for draft-2020-12
  jsonSchema.$schema = JSON_SCHEMA_DRAFT_2020_12
  return jsonSchema
}

/**
 * Round-trip an ArkType Type through JSON Schema:
 *   1. Export the Type to JSON Schema (draft-2020-12)
 *   2. Re-parse the JSON Schema back into an ArkType Type
 *   3. Return the re-parsed Type
 */
export function roundTrip(schema: Type): Type {
  const jsonSchema = exportJsonSchema(schema)
  return jsonSchemaToType(jsonSchema)
}

import { type } from "arktype"
import { roundTrip, exportJsonSchema } from "./roundTrip.js"

function readStdin(): Promise<string> {
  return new Promise((resolve, reject) => {
    let data = ""
    process.stdin.setEncoding("utf8")
    process.stdin.on("data", (chunk: string) => {
      data += chunk
    })
    process.stdin.on("end", () => resolve(data))
    process.stdin.on("error", reject)
  })
}

async function main() {
  const input = await readStdin()
  const { schema: schemaDef, corpus } = JSON.parse(input)

  // Build the original ArkType Type from the definition
  const originalType = type(schemaDef)

  // Export to JSON Schema and round-trip back
  const jsonSchema = exportJsonSchema(originalType)
  const roundTrippedType = roundTrip(originalType)

  // Compare original and round-tripped against the corpus
  const agreements = corpus.map((payload: unknown, index: number) => {
    const originalResult = originalType(payload)
    const roundTrippedResult = roundTrippedType(payload)

    const originalAccept = !(originalResult instanceof type.errors)
    const roundTrippedAccept = !(roundTrippedResult instanceof type.errors)
    const agree = originalAccept === roundTrippedAccept

    return { index, originalAccept, roundTrippedAccept, agree }
  })

  const allAgree = agreements.every((a: { agree: boolean }) => a.agree)

  const output = {
    jsonSchema,
    agreements,
    allAgree,
  }

  process.stdout.write(JSON.stringify(output))
  process.exit(allAgree ? 0 : 1)
}

main().catch((err) => {
  console.error(err)
  process.exit(1)
})

